def main():
    if len(sys.argv) > 1 and sys.argv[1] in ('-h', '--help'):
        print(__doc__)
        return
    report_only = '--report' in sys.argv

    total_files = 0
    total_modified = 0
    total_replacements = 0
    per_pair_hits = {}

    for top, dirs, files in os.walk(ROOT):
        dirs[:] = [d for d in dirs if not should_skip_dir(d)]
        for fn in files:
            if not fn.endswith('.html'):
                continue
            path = os.path.join(top, fn)
            total_files += 1
            with open(path, 'rb') as f:
                c = f.read()
            new = c
            n_this = 0
            for en, zh in PAIRS:
                if en in new:
                    cnt = new.count(en)
                    new = new.replace(en, zh)
                    per_pair_hits[en[:60]] = per_pair_hits.get(en[:60], 0) + cnt
                    n_this += cnt
            if new != c:
                total_replacements += n_this
                if not report_only:
                    with open(path, 'wb') as f:
                        f.write(new)
                total_modified += 1

    print(f'Scanned: {total_files} HTML files')
    if report_only:
        print('(REPORT ONLY - no files modified)')
    print(f'Modified: {total_modified}')
    print(f'Total replacements: {total_replacements}')
    print()
    print('Per-pair hit count (top 30):')
    for en, n in sorted(per_pair_hits.items(), key=lambda x: -x[1])[:30]:
        print(f'  {n:>4}x  {en!r}')


